function isAnagram(s1, s2) {
  return s1.length === s2.length && [...s1].sort().join('') === [...s2].sort().join('');
}

function isAnagramMap(s1, s2) {
  if (s1.length !== s2.length) return false;
  const freq = new Map();
  for (let i = 0; i < s1.length; i++) {
    freq.set(s1[i], (freq.get(s1[i]) || 0) + 1);
    freq.set(s2[i], (freq.get(s2[i]) || 0) - 1);
  }
  return Array.from(freq.values()).every(count => count === 0);
}

function isAnagramTyped(s1, s2) {
  if (s1.length !== s2.length) return false;
  const count1 = new Int16Array(128), count2 = new Int16Array(128);
  for (let i = 0; i < s1.length; i++) {
    count1[s1.charCodeAt(i)]++;
    count2[s2.charCodeAt(i)]++;
  }
  return count1.every((v, i) => v === count2[i]);
}
